using System;
using System.Diagnostics;
using TextAnalysis;

const string SampleText =
    "The quick brown fox jumps over the lazy dog " +
    "A stitch in time saves nine but the early bird catches the worm " +
    "To be or not to be that is the question whether it is nobler in the mind " +
    "All that glitters is not gold and not all those who wander are lost " +
    "The only thing we have to fear is fear itself so let us move forward together";

var analyzer = new TextAnalyzer(SampleText);

// Warmup
for (int i = 0; i < 10_000; i++)
{
    analyzer.AverageWordLength();
    analyzer.WordLengthHistogram();
    analyzer.UniqueWordCount();
}

const int Iterations = 1_000_000;
var sw = new Stopwatch();

Console.WriteLine($"Runtime: {Environment.Version}");
Console.WriteLine($"Iterations: {Iterations:N0}");
Console.WriteLine();

// AverageWordLength
sw.Restart();
for (int i = 0; i < Iterations; i++)
    analyzer.AverageWordLength();
sw.Stop();
Console.WriteLine($"AverageWordLength:    {sw.Elapsed.TotalMilliseconds,10:F2} ms total | {sw.Elapsed.TotalNanoseconds / Iterations,8:F1} ns/op");

// WordLengthHistogram
sw.Restart();
for (int i = 0; i < Iterations; i++)
